# test_deep_get.py
import pytest

# Import the function under test.
# Adjust the import path/name as needed.
from your_module import deep_get


class TestDeepGet:
    def test_happy_path_nested_value(self):
        d = {"a": {"b": {"c": 123}}}
        assert deep_get(d, "a.b.c") == 123

    def test_happy_path_single_key(self):
        d = {"x": 42}
        assert deep_get(d, "x") == 42

    def test_missing_key_returns_default(self):
        d = {"a": {"b": 1}}
        assert deep_get(d, "a.c", default="DEF") == "DEF"

    def test_missing_intermediate_key_returns_default(self):
        d = {"a": {}}
        assert deep_get(d, "a.b.c", default=None) is None
        assert deep_get(d, "a.b.c", default="DEF") == "DEF"

    def test_edge_empty_keys_string_returns_original_dict(self):
        # keys.split('.') -> [''] so loop runs once with key ''.
        d = {"": "value", "other": 1}
        assert deep_get(d, "", default="DEF") == "value"

    def test_edge_trailing_dot_results_in_empty_key_lookup(self):
        d = {"a": {"b": {"": "v"}}}
        assert deep_get(d, "a.b.", default="DEF") == "v"

    def test_error_case_none_d_returns_default_on_first_iteration(self):
        # d is not a dict at the start -> returns default immediately.
        assert deep_get(None, "a.b", default="DEF") == "DEF"

    def test_error_case_non_dict_intermediate_returns_default(self):
        d = {"a": 5}
        assert deep_get(d, "a.b", default="DEF") == "DEF"

    def test_error_case_non_dict_does_not_raise(self):
        d = 10
        assert deep_get(d, "anything", default=None) is None

    def test_default_propagation_when_missing_deeper(self):
        d = {"a": {"b": 7}}
        assert deep_get(d, "a.b.c", default="NOPE") == "NOPE"

    def test_keys_not_str_raises_attribute_error(self):
        # deep_get expects keys to be a str (uses .split)
        with pytest.raises(AttributeError):
            deep_get({"a": 1}, None)

        with pytest.raises(AttributeError):
            deep_get({"a": 1}, 123)
